// // This module decrements its count value on each rising edge of the clock signal (clk). If a reset signal (rst) is asserted, the counter resets to zero.
module top_module(
    input clk,
    input rst,
    output reg [3:0] count
);always @(posedge clk) begin
        if (rst) begin
            count <= 4'b0000;
        end else begin
            count <= count + 1;
        end
    end

endmodule
